import json

result_data = locals().get('var_functions.query_db:10')
if isinstance(result_data, str):
    with open(result_data, 'r') as f:
        articles = json.load(f)
else:
    articles = result_data

sports_keywords = [
    'sport', 'sports', 'game', 'team', 'player', 'athlete', 'season',
    'championship', 'tournament', 'league', 'football', 'basketball',
    'baseball', 'soccer', 'tennis', 'golf', 'hockey', 'cricket', 'rugby'
]

sports_articles = []
for article in articles:
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()
    text = title + ' ' + desc

    matches = 0
    for keyword in sports_keywords:
        if keyword in text:
            matches += 1

    if matches >= 1:
        sports_articles.append({
            'title': article.get('title'),
            'desc': article.get('description'),
            'length': len(article.get('description', ''))
        })

if sports_articles:
    max_len = 0
    max_title = ''
    for article in sports_articles:
        if article['length'] > max_len:
            max_len = article['length']
            max_title = article['title']
    result = max_title
else:
    result = 'No sports articles found'

print('__RESULT__:')
print(json.dumps(result))

